+    echo "    \"cat $(json_escape "$runner_output_root")/*/test262_case_execution.jsonl\",";
     echo "    \"cat $(json_escape "$canonical_hwm_path")\",";
     echo "    \"${0} ci\"";
     echo '  ]';
